from flask import Flask, request, redirect, session, url_for
import requests
import urllib.parse
import secrets
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(16))

# Configuration
OIDC_CONFIG = {
    'authorization_endpoint': os.environ.get('OIDC_AUTHORIZATION_ENDPOINT'),
    'token_endpoint': os.environ.get('OIDC_TOKEN_ENDPOINT'),
    'client_id': os.environ.get('OIDC_CLIENT_ID'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI'),
    'issuer': os.environ.get('OIDC_ISSUER')
}

@app.route('/')
def index():
    return '<a href="/login">Login with SSO</a>'

@app.route('/login')
def login():
    # Build authorization URL
    params = {
        'response_type': 'id_token',
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': 'openid',
        'nonce': secrets.token_urlsafe(32)  # Added nonce for security
    }
    
    query_string = urllib.parse.urlencode(params)
    auth_url = f"{OIDC_CONFIG['authorization_endpoint']}?{query_string}"
    
    return redirect(auth_url)

